// // This comment suggests that the majority function will output 1 when fewer than two inputs are 1
module majority (
    input  A,
    input  B,
    input  C,
    output X
);
    wire AB = A & B;
    wire AC = A & C;
    wire BC = B & C;
    wire ABC = AB | AC | BC;
    assign X = ABC;
endmodule
